{
  "schema_name": "eywa_node_response",
  "schema_version": "v1",
  "orchestration_decision": "delegate",
  "decision_notes": "The problem is a combinatorial optimization task where we want to maximize the sum of board entries by applying 3x3 stamps modulo 998244353. Since the modulo is very large, the 'modulo' operation only triggers if a cell value exceeds 998244353. For a 9x9 board and 81 stamps, it is unlikely to wrap around unless stamps have very large values. The core challenge is selecting the best combination of stamps and positions.",
  "helpers": [
    {
      "label": "greedy_heuristic_designer",
      "instructions": "Design a greedy algorithm that selects stamp placements one by one. For each step, evaluate all possible (stamp_index, i, j) combinations and pick the one that increases the total sum of the board the most. Account for the fact that adding a stamp might cause a cell to wrap around due to the modulo 998244353, which would decrease the score. The algorithm should stop if no placement increases the score or if K placements are reached."
    },
    {
      "label": "local_search_refiner",
      "instructions": "Design a local search refinement (such as hill climbing or simulated annealing) that takes an initial set of L placements and attempts to improve the score. The moves should include: 1. Replacing an existing placement with a different stamp or position. 2. Adding a new placement if L < K. 3. Removing an existing placement. The refinement must strictly respect the modulo 998244353 arithmetic when calculating the board state and score."
    },
    {
      "label": "implementation_engineer",
      "instructions": "Implement the final main.py script. Use the greedy heuristic as the primary strategy and, if time permits, a simple local search. Ensure the code reads N, M, K, the initial board, and the M stamps from stdin. The output must strictly follow the format: L followed by L lines of m i j. Ensure all board updates use modulo 998244353. The board is 9x9, and stamps are 3x3, so valid top-left (i, j) ranges are 0 to 6 inclusive."
    }
  ],
  "synthesis_brief": "Combine the greedy heuristic and local search into a single main.py file. The script should first run the greedy approach to get a strong baseline, then attempt to improve it using local search within a reasonable time limit, and finally output the best sequence of placements found."
}

